#include <iostream>

int add(int a, int b) {
  return a + b;
}

double add(double a, double b) {
  return a + b;
}

int main() {
  int intResult = add(5, 3);
  double doubleResult = add(5.5, 3.2);
  std::cout << "Integer sum: " << intResult << std::endl;
  std::cout << "Double sum: " << doubleResult << std::endl;
  return 0;
}
// Output:
// Integer sum: 8
// Double sum: 8.7

#include <iostream>

int multiply(int a, int b) {
  return a * b;
}

int multiply(int a, int b, int c) {
  return a * b * c;
}

int main() {
  int result1 = multiply(2, 3);
  int result2 = multiply(2, 3, 4);
  std::cout << "Two numbers: " << result1 << std::endl;
  std::cout << "Three numbers: " << result2 << std::endl;
  return 0;
}
// Output:
// Two numbers: 6
// Three numbers: 24

#include <iostream>

void print(std::string message) {
  std::cout << "Message: " << message << std::endl;
}

void print(int number) {
  std::cout << "Number: " << number << std::endl;
}

int main() {
  print("Hello!");
  print(42);
  return 0;
}
// Output:
// Message: Hello!
// Number: 42

